insert into quests (day_number, title, subtitle, description, tier, xp_value, is_boss) values
(1, 'Hello, World!', 'Start here', 'Learn what Python is, why programs run line by line, and print your first message: Hello World. You will understand that code is just instructions the computer reads in order.', 'beginner', 25, false),
(2, 'Simple print statements', 'Show text on screen', 'Learn why print() is useful for debugging and for showing a player what is happening in a program. Try several short messages so you can see how output works.', 'beginner', 25, false),
(3, 'Variables', 'Store values', 'Understand why variables matter: they let your program remember information like a name or score so you can use it again later without typing it over and over.', 'beginner', 25, false),
(4, 'Input basics', 'Talk to the user', 'See how input() lets your code respond to a real person. This is the first step toward making your program feel interactive instead of static.', 'beginner', 25, false),
(5, 'Numbers', 'Simple math', 'Learn why Python treats numbers differently than text. You will add and subtract so you can build scores, counters, and game values.', 'beginner', 25, false),
(6, 'Strings', 'Work with text', 'Understand how Python handles text and why strings are the building blocks of names, messages, and dialogue in games and apps.', 'beginner', 25, false),
(7, 'Mini challenge 1', 'First checkpoint', 'Build a tiny greeting script using print and input. The goal is to connect output, input, and variables into a simple conversation with the user.', 'boss', 100, true),
(8, 'Lists', 'Store a few items', 'Learn why lists are useful when you need to keep several related values together, like items in an inventory or steps in a quest.', 'beginner', 25, false),
(9, 'If statements', 'Make choices', 'See how Python makes decisions. Conditionals are what let games branch into different outcomes based on player choices or values.', 'beginner', 25, false),
(10, 'Simple loops', 'Repeat actions', 'Learn why loops exist: they stop you from writing the same code many times. Use a for loop to repeat a message and see the pattern.', 'beginner', 25, false),
(11, 'While loops', 'Keep going', 'Understand the idea of repetition until something changes. While loops are great when you do not know exactly how many turns a task will take.', 'beginner', 25, false),
(12, 'Dictionaries', 'Label data', 'Learn why key-value pairs are powerful when you want to name pieces of information clearly, like character stats or settings.', 'beginner', 25, false),
(13, 'Simple functions', 'Reuse code', 'Functions let you group steps together and reuse them. This is one of the most important ideas in programming because it keeps code organized and readable.', 'beginner', 25, false),
(14, 'Mini challenge 2', 'Second checkpoint', 'Combine variables, input, and conditionals in a small script. This checkpoint focuses on how the pieces fit together, not just on getting an answer.', 'boss', 100, true),
(15, 'Debugging', 'Fix mistakes', 'Read error messages and learn why bugs happen. Debugging is part of programming, and understanding errors helps you improve faster than guessing.', 'beginner', 25, false),
(16, 'Lists in depth', 'Work with more items', 'Practice adding, removing, and looping through list values so you understand how programs handle collections of data.', 'beginner', 25, false),
(17, 'More strings', 'Clean text', 'Learn common text tools like strip, split, replace, and join, and why they matter when cleaning or formatting user input.', 'beginner', 25, false),
(18, 'More functions', 'Better reuse', 'Pass values into functions and return answers. This is where functions start to feel like real tools instead of just shortcuts.', 'beginner', 25, false),
(19, 'Files', 'Save and load', 'Understand why files matter: they let your program remember things after it closes. This is what makes progress and saved data possible.', 'beginner', 25, false),
(20, 'Errors and try/except', 'Stay calm', 'Learn how to handle mistakes without crashing. Good programs expect errors and recover from them when possible.', 'beginner', 25, false),
(21, 'Mini challenge 3', 'Third checkpoint', 'Build a tiny quiz question and score it. This checkpoint checks whether you can combine input, logic, and output into a small workflow.', 'boss', 100, true),
(22, 'Modules', 'Use built-ins', 'Import a Python module and use one function. Modules exist so you can reuse code that other people already built and tested.', 'beginner', 25, false),
(23, 'Project planning', 'Prepare to build', 'Choose a small final project and sketch it out. Planning matters because it helps you break a big idea into smaller steps.', 'beginner', 25, false),
(24, 'Classes basics', 'Objects', 'See how classes create reusable objects. This is the first step toward modeling characters, enemies, and items in a game.', 'beginner', 25, false),
(25, 'Capstone helpers', 'Build a demo', 'Use what you learned to make a tiny app and see how the earlier lessons come together.', 'beginner', 25, false),
(26, 'Review day', 'Practice', 'Repeat the basics and strengthen weak spots. Review helps the ideas stick and makes the later quests easier.', 'beginner', 25, false),
(27, 'Final mini project', 'Fourth checkpoint', 'Make a small Python app with input and output. The goal is to use the tools you learned to build something that feels complete.', 'boss', 100, true),
(28, 'Celebrate and continue', 'You are ready', 'Review your progress and plan the next step. By now you should understand how Python scripts are built and how to keep learning.', 'beginner', 25, false)
